payload.raw:
{
  "layout": "timeline",
  "title": "创新设计",
  "events": [
    {
      "date": "第1–2月",
      "title": "材料与硬件攻坚",
      "description": "完成柔性传感器微结构设计、液态金属-聚氨酯复合材料制备及信号标定，构建0.1mm级空间分辨率的混合传感架构，配备光纤与IMU单元。"
    },
    {
      "date": "第3月",
      "title": "算法开发与融合协议构建",
      "description": "开发分层CNN-LSTM手势识别模型，结合自适应滑动窗口与噪声抑制模块，实现实测>98.2%准确率；同步建立视觉-触觉-听觉统一时空对齐的多模态融合引擎，提升跨平台部署效率60%。"
    },
    {
      "date": "第4月",
      "title": "系统集成与反馈闭环搭建",
      "description": "完成软硬件联调，嵌入微型电磁致动器阵列与半导体温控模块，实现压力/温度微秒级调控；构建感知-意图-反馈闭环，并接入H-Box全息舱、李未可眼镜等合作设备接口。"
    },
    {
      "date": "第5–6月",
      "title": "多场景验证与体验优化",
      "description": "在工业远程操控与虚拟实训等真实场景开展压力测试，基于用户反馈迭代优化交互逻辑，形成可复用的元宇宙多模态交互标准接口。"
    }
  ]
}

